import subprocess
import os

def generate_requirements_txt_with_hashes():
    """Generate a requirements.txt file with hashes using pip-tools."""
    # Install pip-tools if not already installed
    try:
        subprocess.check_call(['pip', 'install', '--upgrade', 'pip-tools'])
    except subprocess.CalledProcessError as e:
        print(f"Failed to install pip-tools: {e}")
        return

    # Generate requirements.txt with hashes
    try:
        subprocess.check_call(['pip-compile', '--generate-hashes', '-o', 'requirements.txt'])
    except subprocess.CalledProcessError as e:
        print(f"Failed to generate requirements.txt: {e}")

def update_requirements_txt_with_hashes():
    """Update the requirements.txt file with the latest compatible versions and hashes."""
    try:
        subprocess.check_call(['pip-compile', '--upgrade', '--generate-hashes'])
    except subprocess.CalledProcessError as e:
        print(f"Failed to update requirements.txt: {e}")

def generate_poetry_lock_file():
    """Generate a Poetry lock file with consistent dependency versions."""
    try:
        subprocess.check_call(['poetry', 'lock'])
    except subprocess.CalledProcessError as e:
        print(f"Failed to generate poetry.lock: {e}")

def update_poetry_lock_file():
    """Update the Poetry lock file with the latest compatible versions."""
    try:
        subprocess.check_call(['poetry', 'update'])
    except subprocess.CalledProcessError as e:
        print(f"Failed to update poetry.lock: {e}")

